export interface StorageProvider {
  get(key: string): Promise<string | null>;
  set(key: string, value: string): Promise<void>;
  remove(key: string): Promise<void>;
}

export class IndexedDBProvider implements StorageProvider {
  private dbName = "DeviceFingerprinting";
  private version = 1;
  private storeName = 'identifiers';


  async get(key: string): Promise<string | null> {
    return new Promise((resolve, reject) => {
      try {
        const request = indexedDB.open(this.dbName, this.version);
        request.onerror = () => resolve(null);

        request.onsuccess = () => {
          const db = request.result;
          const transaction = db.transaction([this.storeName], 'readonly');
          const store = transaction.objectStore(this.storeName);
          const getRequest = store.get(key);

          getRequest.onsuccess = () => {
            resolve(getRequest.result?.value || null);
          };
          getRequest.onerror = () => resolve(null);
        }

        request.onupgradeneeded = () => {
          const db = request.result;
          if (!db.objectStoreNames.contains(this.storeName)) {
            db.createObjectStore(this.storeName, { keyPath: 'key' });
          }
        }
      } catch (error) {
        resolve(null);
      }
    });
  }

  async set(key: string, value: string): Promise<void> {
    return new Promise((resolve, reject) => {
      try {
        const request = indexedDB.open(this.dbName, this.version);

        request.onsuccess = () => {
          const db = request.result;
          const transaction = db.transaction([this.storeName], 'readwrite');
          const store = transaction.objectStore(this.storeName);
          const putRequest = store.put({ key, value });

          putRequest.onsuccess = () => resolve();
          putRequest.onerror = () => resolve();
        }
        request.onerror = () => reject(request.error);
      } catch (error) {
        reject(error);
      }
    });
  }
  remove(key: string): Promise<void> {
    throw new Error("Method not implemented.");
  }

}

export class StorageManager {
  private providers: StorageProvider[];
  constructor(providers: StorageProvider[] = [new IndexedDBProvider()]) {
    this.providers = providers;
  }

  async get(key: string): Promise<string | null> {
    for (const provider of this.providers) {
      try {
        const value = await provider.get(key);
        if (value) return value;
      } catch (error) {
        continue;
      }
    }
    return null;
  }

  async set(key: string, value: string): Promise<void> {
    const error: Error[] = [];

    for (const provider of this.providers) {
      try {
        await provider.set(key, value);
        return;
      } catch (err) {
        error.push(err instanceof Error ? err : new Error(String(err)));
      }
    }
    throw new Error(`All storage providers failed: ${error.map(e => e.message).join('; ')}`);
  }

}