import { AbstractCollector } from "../base-collector";
import { StorageManager } from "../../storage/storage-manager";

export class CryptoKeyCollector extends AbstractCollector<Promise<string | null> | null> {
  private readonly STORAGE_KEY = 'device_keypair';
  private storageManager: StorageManager;

  constructor(storageManager: StorageManager) {
    super();
    this.storageManager = storageManager;
  }

  isAvailable(): boolean {
    throw new Error("Method not implemented.");
  }

  async collect(): Promise<string | null> {
    try {
      let keyPair = await this.getStoredKeyPair();
      if (!keyPair) {
        keyPair = await this.generateKeyPair();
        if (keyPair) {
          await this.storeKeyPair(keyPair);
        }
      }

      if (keyPair) {
        const publicKeyBuffer = await crypto.subtle.exportKey('spki', keyPair.publicKey);
        return this.arrayBufferToPEM(publicKeyBuffer, 'PUBLIC KEY');
      }
      return null
    } catch (error) {
      console.warn('WebCrypto not available or failed:', error);
      return null;
    }
  }

  private async generateKeyPair(): Promise<CryptoKeyPair | null> {
    try {
      return await crypto.subtle.generateKey(
        {
          name: 'RSA-PSS',
          modulusLength: 2048,
          publicExponent: new Uint8Array([0x01, 0x00, 0x01]),
          hash: 'SHA-256',
        },
        true,
        ['sign', 'verify']
      );
    } catch (error) {
      console.warn('Failed to generate key pair:', error);
      return null;

    }
  }

  private async getStoredKeyPair(): Promise<CryptoKeyPair | null> {
    try {
      const keyPairData = await this.storageManager.get(this.STORAGE_KEY);
      if (!keyPairData) return null;
      const { publicKey, privateKey } = JSON.parse(keyPairData);
      const importedPublicKey = await crypto.subtle.importKey(
        'spki',
        this.base64ToArrayBuffer(publicKey),
        {
          name: 'RSA-PSS',
          hash: 'SHA-256',
        },
        true,
        ['verify']
      );

      const importedPrivateKey = await crypto.subtle.importKey(
        'pkcs8',
        this.base64ToArrayBuffer(privateKey),
        {
          name: 'RSA-PSS',
          hash: 'SHA-256',
        },
        true,
        ['sign']
      );

      return { publicKey: importedPublicKey, privateKey: importedPrivateKey };
    } catch (error) {
      return null
    }
  }

  private async storeKeyPair(keyPair: CryptoKeyPair): Promise<void> {
    const publicKeyBuffer = await crypto.subtle.exportKey('spki', keyPair.publicKey);
    const privateKeyBuffer = await crypto.subtle.exportKey('pkcs8', keyPair.privateKey);
    const keyPairData = JSON.stringify({
      publicKey: this.arrayBufferToBase64(publicKeyBuffer),
      privateKey: this.arrayBufferToBase64(privateKeyBuffer),
    });
    await this.storageManager.set(this.STORAGE_KEY, keyPairData);
  }

  private arrayBufferToPEM(buffer: ArrayBuffer, label: string): string {
    const base64 = this.arrayBufferToBase64(buffer);
    return `-----BEGIN ${label}-----\n${base64.match(/.{1,64}/g)?.join('\n')}\n-----END ${label}-----`;
  }

  private arrayBufferToBase64(buffer: ArrayBuffer): string {
    const bytes = new Uint8Array(buffer);
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binary = atob(base64);
    const buffer = new ArrayBuffer(binary.length);
    const bytes = new Uint8Array(buffer);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    return buffer;
  }
}