export interface BaseCollector<T> {
  collect(): Promise<T> | T;
  isAvailable(): boolean;
}

export abstract class AbstractCollector<T> implements BaseCollector<T> {
  abstract collect(): Promise<T> | T;
  abstract isAvailable(): boolean;

  protected handleError<R>(fn: () => R, fallback: R): R {
    try {
      return fn();
    } catch (error) {
      console.warn(`Collector error in ${this.constructor.name}:`, error);
      return fallback;
    }
  }
}