import { NetworkData } from '../types/base-types';
import { AbstractCollector } from './base-collector';

export class NetworkCollector extends AbstractCollector<NetworkData> {
  isAvailable(): boolean {
    return 'connection' in navigator;
  }

  collect(): NetworkData {
    if (!this.isAvailable()) {
      return {
        effectiveType: null,
        downlink: null,
        rtt: null,
        saveData: false
      };
    }

    const connection = (navigator as any).connection;
    return this.handleError(() => ({
      effectiveType: connection?.effectiveType || 'unknown',
      downlink: connection?.downlink || null,
      rtt: connection?.rtt || null,
      saveData: connection?.saveData || false
    }), {
      effectiveType: undefined,
      downlink: undefined,
      rtt: undefined,
      saveData: undefined
    });
  }
}

export function collectNetwork(): NetworkData {
  const collector = new NetworkCollector();
  return collector.collect();
}