import { DeterministicIdentifiers } from "../types/web-telemetry";
import { CookieDeviceCollector } from "./identifier/cookie-device";
import { CryptoKeyCollector } from "./identifier/crypto-key";
import { InstallationIdCollector } from "./identifier/installation-id";
import { SignedTokenCollector } from "./identifier/signed-token";
import { WebAuthnCollector } from "./identifier/webauth";
import { StorageManager } from "../storage/storage-manager";

export class DeterministicCollector {
  private storageManager: StorageManager;
  private installationIdCollector: InstallationIdCollector;
  private cryptoKeyCollector: CryptoKeyCollector;
  private cookieDeviceCollector: CookieDeviceCollector;
  private webauthnCollector: WebAuthnCollector;
  private signedTokenCollector: SignedTokenCollector;

  constructor() {
    this.storageManager = new StorageManager();
    this.installationIdCollector = new InstallationIdCollector(this.storageManager);
    this.cryptoKeyCollector = new CryptoKeyCollector(this.storageManager);
    this.cookieDeviceCollector = new CookieDeviceCollector();
    this.webauthnCollector = new WebAuthnCollector();
    this.signedTokenCollector = new SignedTokenCollector();
  }

  async collect(): Promise<DeterministicIdentifiers> {
    const [
      browser_installation_id,
      public_key_pem,
      cookie_device_id,
      webauthn_credential_id,
      signed_client_token
    ] = await Promise.all([
      this.installationIdCollector.collect(),
      this.cryptoKeyCollector.collect(),
      this.cookieDeviceCollector.collect(),
      this.webauthnCollector.collect(),
      this.signedTokenCollector.collect()
    ]);

    return {
      browser_installation_id,
      public_key_pem,
      cookie_device_id,
      webauthn_credential_id,
      signed_client_token,
    };
  }
}