import { ScreenData } from '../types/base-types';
import { AbstractCollector } from './base-collector';

export class ScreenCollector extends AbstractCollector<ScreenData> {
  isAvailable(): boolean {
    return typeof screen !== 'undefined';
  }

  collect(): ScreenData {
    if (!this.isAvailable()) {
      throw new Error('Screen API not available');
    }

    return this.handleError(() => ({
      width: screen.width,
      height: screen.height,
      colorDepth: screen.colorDepth,
      pixelDepth: screen.pixelDepth,
      devicePixelRatio: window.devicePixelRatio || 1,
      orientation: screen.orientation?.type || 'unknown'
    }), {
      width: 0,
      height: 0,
      colorDepth: 0,
      pixelDepth: 0,
      devicePixelRatio: 1,
      orientation: 'unknown'
    });
  }
}

export function collectScreen(): ScreenData {
  const collector = new ScreenCollector();
  return collector.collect();
}